+                .deferred_touches
+                .lock()
+                .unwrap_or_else(std::sync::PoisonError::into_inner);
+            touches.drain().collect()
+        };
+        let mut last = self
+            .last_touch_flush
+            .lock()
+            .unwrap_or_else(std::sync::PoisonError::into_inner);
+        *last = Instant::now();
+        drained
